import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Sanitize user input to prevent XSS attacks
        String sanitizedInput = sanitizeInput(userInput);

        // Output sanitized input
        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>User Input: " + sanitizedInput + "</h1>");
        out.println("</body>");
        out.println("</html>");
    }

    private String sanitizeInput(String input) {
        // Implement proper sanitization logic here
        // For example, you can use OWASP Java Encoder library or HTML escaping methods

        return encodeForHTML(input);
    }

    private String encodeForHTML(String input) {
        return org.owasp.encoder.Encode.forHtml(input);
    }
}

